        d.update(extra)
        return UserPIIMessage(
            user_id=d["user_id"],
            email=d["email"],
            phone=d["phone"],
            address=d["address"],
            event_type=d.get("event_type", "user_pii"),
            message_id=d.get("message_id", str(uuid.uuid4())),
            occurred_at_ms=d.get("occurred_at_ms", _now_ms()),
            schema_version=d.get("schema_version", "1.0"),
        )
